ors'=>'Culorile butoanelor','Primary Button Background'=>'Fundalul butonului primar','Primary Button Text'=>'Textul butonului primar','Primary Button Hover'=>'Trecerea cu mouse-ul butonului primar','Secondary Button Background'=>'Fundalul butonului secundar','Secondary Button Text'=>'Textul butonului secundar','Secondary Button Hover'=>'Trecerea cu mouse-ul butonului secundar','Admin menu colors'=>'Culorile meniului de admin','Menu Background'=>'Fundalul meniului','Menu Text Color'=>'Culoarea textului din meniu','Menu Icon Color'=>'Culoarea icoanei din meniu','Menu Hover Background'=>'Fundalul hover al meniului','Menu Hover Text'=>'Textul hover al meniului','Current Menu Background'=>'Fundalul meniului curent','Current Menu Text'=>'Textul meniului curent','Submenu Background'=>'Fundalul submeniu','Submenu Text Color'=>'Culoarea textului din submeniu','Admin bar colors'=>'Culorile barei de admin','Admin Bar Background'=>'Fundalul barei de admin','Admin Bar Text'=>'Textul barei de admin','Admin Bar Icon'=>'Icoana barei de admin','Admin Bar Hover Background'=>'Fundalul hover al barei de admin','Admin Bar Hover Text'=>'Textul hover al barei de admin','Dashboard Widgets'=>'Widget-uri dashboard','Dashboard widget colors'=>'Culorile widget-urilor dashboard','Widget Background'=>'Fundalul widget-ului','Widget Border'=>'Marginea widget-ului','Widget Header Background'=>'Fundalul antetului widget-ului','Widget Title Text'=>'Textul titlului widget-ului','Widget Body Text'=>'Textul corpului widget','Widget Link'=>'Link widget','Widget Link Hover'=>'Link widget la trecerea cu mouse-ul','Advanced'=>'Avansat','Custom selector color rules'=>'Reguli de culoare pentru selector personalizat','Classic Editor %s Restrictions'=>'Restricții Editor Classic %s','No metaboxes found for %1s. %2s Click here %3s to visit the %4s screen and refresh this page afterwards to load the new metaboxes.'=>'Nu s-au găsit metabox-uri pentru %1s. %2s Fă clic aici %3s pentru a vizita ecranul %4s și reîmpros